import React, {useMemo} from "react";
import type {ICardComponent} from "@lmb-it/kitsconcerto-types";
import {ResponsiveElement, useSeparator} from "../../factory";
import {useComponentDefaults} from "../../hooks";

/**
 * Card component — self-contained, no PrimeReact dependency.
 *
 * Theme element slots via kitsTheme.components.Card:
 *   root     — outer container (goes through ResponsiveElement)
 *   header   — header wrapper div (styled via ResponsiveElement)
 *   title    — title wrapper (styled via ResponsiveElement)
 *   subTitle — subtitle wrapper (styled via ResponsiveElement)
 *   content  — children wrapper (styled via ResponsiveElement)
 *   footer   — footer wrapper (styled via ResponsiveElement)
 *
 * All slot styles go through the full KitsConcerto CSS pipeline,
 * supporting shorthand props (p, m, px, etc.), theme tokens (color="primary"),
 * pseudo-classes (_hover), and responsive values.
 */
const Card = (rawProps: ICardComponent<Record<string, any>>) => {
    const {mergedProps: props, themeStyle, elementStyles} = useComponentDefaults('Card', rawProps);
    const {
        title,
        subTitle,
        header,
        footer,
        className,
        variant = 'elevated',
        size = 'md',
        ref,
        children,
        localProps,
        style,
        ...rest
    } = props;

    const {cssProps, nativeProps} = useSeparator<any>({variant, size, ...rest});
    const {entering, exiting, ...restNativeProps} = nativeProps;

    // Resolve render content
    const resolvedHeader = typeof header === 'function' ? header(props) : header;
    const resolvedTitle = typeof title === 'function' ? title(props) : title;
    const resolvedSubTitle = typeof subTitle === 'function' ? subTitle(props) : subTitle;
    const resolvedFooter = typeof footer === 'function'
        ? (localProps ? footer(localProps) : null)
        : footer;

    const classes = useMemo(() => {
        const c: string[] = [];
        if (className) c.push(className);
        return c.join(" ");
    }, [className]);

    // Root styles: themeStyle (lowest) → cssProps → style (highest)
    const rootCss = {
        ...themeStyle,
        ...cssProps,
        ...style,
    };

    // Check if a slot has any styles defined
    const hasSlotStyle = (slotName: string) => {
        const s = elementStyles[slotName];
        return s && Object.keys(s).length > 0;
    };

    return (
        <ResponsiveElement
            ref={ref}
            entering={entering}
            exiting={exiting}
            additionalClasses={classes}
            //@ts-ignore
            cssProps={rootCss}
            nativeProps={restNativeProps}
        >
            {/* Header */}
            {resolvedHeader && (
                hasSlotStyle('header')
                    ? <ResponsiveElement cssProps={elementStyles.header} nativeProps={{}}>{resolvedHeader}</ResponsiveElement>
                    : resolvedHeader
            )}

            {/* Title */}
            {resolvedTitle && (
                hasSlotStyle('title')
                    ? <ResponsiveElement cssProps={elementStyles.title} nativeProps={{}}>{typeof resolvedTitle === 'string' ? resolvedTitle : resolvedTitle}</ResponsiveElement>
                    : <>{typeof resolvedTitle === 'string' ? resolvedTitle : resolvedTitle}</>
            )}

            {/* SubTitle */}
            {resolvedSubTitle && (
                hasSlotStyle('subTitle')
                    ? <ResponsiveElement cssProps={elementStyles.subTitle} nativeProps={{}}>{typeof resolvedSubTitle === 'string' ? resolvedSubTitle : resolvedSubTitle}</ResponsiveElement>
                    : <>{typeof resolvedSubTitle === 'string' ? resolvedSubTitle : resolvedSubTitle}</>
            )}

            {/* Content (children) */}
            {hasSlotStyle('content')
                ? <ResponsiveElement cssProps={elementStyles.content} nativeProps={{}}>{children}</ResponsiveElement>
                : children
            }

            {/* Footer */}
            {resolvedFooter && (
                hasSlotStyle('footer')
                    ? <ResponsiveElement cssProps={elementStyles.footer} nativeProps={{}}>{resolvedFooter}</ResponsiveElement>
                    : resolvedFooter
            )}
        </ResponsiveElement>
    );
};

export default Card;
